using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

var noteTaker = new NoteTakingTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchWebAsync),
    AIFunctionFactory.Create(WebSearchTool.FetchWebPageAsync),
    AIFunctionFactory.Create(noteTaker.SaveNote),
    AIFunctionFactory.Create(noteTaker.GetNotes),
};

var modelId = "gpt-4o-mini-2024-07-18";
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = chatClient.AsAIAgent(
    instructions: """
        You are a thorough research agent. When given a topic to research:

        1. Search the web for information using multiple targeted queries
        2. Fetch relevant web pages for detailed information when URLs look promising
        3. Save important findings as notes with descriptive titles
        4. Perform at least 3 different searches to cover various aspects of the topic
        5. After gathering enough information, retrieve all your notes
        6. Write a comprehensive, well-structured summary of your findings

        Always cite your sources. Be thorough but concise in your final summary.
        """,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking",
    tools: tools);

Console.WriteLine($"\nResearching: \"{topic}\"...\n");

var runOptions = new ChatClientAgentRunOptions(
    new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    });

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic thoroughly and provide a comprehensive summary: {topic}",
    session: null,
    options: runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();

