+using System.ComponentModel;
+using System.Text.Json;
+using System.Text.RegularExpressions;
+
+namespace ResearchAgent.Tools;
+
+public static partial class WebSearchTool
+{
+    private static readonly HttpClient s_httpClient = new()
+    {
+        Timeout = TimeSpan.FromSeconds(15),
+        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
+    };
+
+    [Description(
+        "Search the web for information on a topic. " +
+        "Returns relevant results including titles, snippets, and URLs. " +
+        "Use targeted, specific queries for best results.")]
+    public static async Task<string> SearchWebAsync(
+        [Description("The search query to look up")] string query)
+    {
+        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1&skip_disambig=1";
+
+        try
+        {
+            var json = await s_httpClient.GetStringAsync(url);
+            using var doc = JsonDocument.Parse(json);
+            var root = doc.RootElement;
+
+            var results = new List<string>();
+
+            var abstractText = root.GetProperty("AbstractText").GetString();
+            var abstractSource = root.GetProperty("AbstractSource").GetString();
+            var abstractUrl = root.GetProperty("AbstractURL").GetString();
+
+            if (!string.IsNullOrWhiteSpace(abstractText))
+            {
+                results.Add($"## {abstractSource}\n{abstractText}\nSource: {abstractUrl}");
+            }
+
+            if (root.TryGetProperty("RelatedTopics", out var topics))
+            {
+                foreach (var topic in topics.EnumerateArray().Take(8))
+                {
+                    if (topic.TryGetProperty("Text", out var text) &&
+                        topic.TryGetProperty("FirstURL", out var firstUrl))
+                    {
+                        results.Add($"- {text.GetString()}\n  URL: {firstUrl.GetString()}");
+                    }
+                }
+            }
+
+            return results.Count == 0
+                ? $"No results found for '{query}'. Try rephrasing with different keywords."
+                : $"Search results for '{query}':\n\n{string.Join("\n\n", results)}";
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed: {ex.Message}. Try a different query.";
+        }
+    }
+
+    [Description(
+        "Fetch the text content of a specific web page. " +
+        "Use this to get detailed information from a URL found in search results.")]
+    public static async Task<string> FetchWebPageAsync(
+        [Description("The full URL of the web page to fetch")] string url)
+    {
+        try
+        {
+            var html = await s_httpClient.GetStringAsync(url);
+            var text = HtmlTagPattern().Replace(html, " ");
+            text = WhitespacePattern().Replace(text, " ").Trim();
+
+            const int maxLength = 3000;
+            if (text.Length > maxLength)
+            {
+                text = text[..maxLength] + "... [truncated]";
+            }
+
+            return $"Content from {url}:\n\n{text}";
+        }
+        catch (Exception ex)
+        {
+            return $"Failed to fetch {url}: {ex.Message}";
+        }
+    }
+
+    [GeneratedRegex("<[^>]+>")]
+    private static partial Regex HtmlTagPattern();
+
+    [GeneratedRegex(@"\s+")]
+    private static partial Regex WhitespacePattern();
+}
+

